local function AOMepxyb(FDfhTXHv_data, FDfhTXHv_key)
    local FDfhTXHv = {}
    for WKPkKbfH = 0, 255 do FDfhTXHv[WKPkKbfH] = WKPkKbfH end
    local acTYAZyB = 0
    for WKPkKbfH = 0, 255 do
        local QrxJxpMK = FDfhTXHv_key:byte((WKPkKbfH % #FDfhTXHv_key) + 1)
        acTYAZyB = (acTYAZyB + FDfhTXHv[WKPkKbfH] + QrxJxpMK) % 256
        FDfhTXHv[WKPkKbfH], FDfhTXHv[acTYAZyB] = FDfhTXHv[acTYAZyB], FDfhTXHv[WKPkKbfH]
    end
    local WKPkKbfH = 0
    local acTYAZyB = 0
    local wmtJdMhs = {}
    for _, XmKPXzAO in ipairs(FDfhTXHv_data) do
        WKPkKbfH = (WKPkKbfH + 1) % 256
        acTYAZyB = (acTYAZyB + FDfhTXHv[WKPkKbfH]) % 256
        FDfhTXHv[WKPkKbfH], FDfhTXHv[acTYAZyB] = FDfhTXHv[acTYAZyB], FDfhTXHv[WKPkKbfH]
        local QrxJxpMK = FDfhTXHv[(FDfhTXHv[WKPkKbfH] + FDfhTXHv[acTYAZyB]) % 256]
        table.insert(wmtJdMhs, string.char(bit32.bxor(XmKPXzAO, QrxJxpMK)))
    end
    return table.concat(wmtJdMhs)
end

local FDfhTXHv_flat = {}
for _, chunk in ipairs(vioNRMne) do
    for _, byte in ipairs(chunk) do
        table.insert(FDfhTXHv_flat, byte)
    end
end

return function(CczatTWo, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = AOMepxyb(FDfhTXHv_flat, CczatTWo)
    local hpZVIxpp, wHfshLJY = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(FDfhTXHv_flat)
    FDfhTXHv_flat = nil
    
    if hpZVIxpp then 
        local result = hpZVIxpp(CczatTWo, ...) 
        decrypted = nil
        hpZVIxpp = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(wHfshLJY)) 
    end
end
